import '../lib/audit_event.dart';
import '../lib/audit_pager.dart';

void check(bool condition, String message) {
  if (!condition) {
    throw StateError(message);
  }
}

void main() {
  final tiedAt = DateTime.utc(2026, 4, 20, 12);
  final events = <AuditEvent>[
    AuditEvent(id: 'site|west', occurredAt: tiedAt, action: 'updated'),
    AuditEvent(
      id: 'newest',
      occurredAt: DateTime.utc(2026, 4, 20, 13),
      action: 'created',
    ),
    AuditEvent(id: 'site:north', occurredAt: tiedAt, action: 'updated'),
    AuditEvent(
      id: 'oldest',
      occurredAt: DateTime.utc(2026, 4, 20, 11),
      action: 'created',
    ),
    AuditEvent(id: 'site/east', occurredAt: tiedAt, action: 'updated'),
  ];

  final pager = AuditPager();
  final visited = <String>[];
  String? cursor;
  var pageCount = 0;
  while (true) {
    final page = pager.page(events, limit: 2, after: cursor);
    check(page.events.isNotEmpty, 'a nonterminal cursor walk makes progress');
    visited.addAll(page.events.map((event) => event.id));
    pageCount += 1;
    check(pageCount <= 4, 'cursor traversal terminates');
    if (page.nextCursor == null) {
      break;
    }
    check(page.nextCursor != cursor, 'each continuation advances');
    cursor = page.nextCursor;
  }

  check(
    visited.join(',') == 'newest,site/east,site:north,site|west,oldest',
    'compound boundaries visit every tied record once in total order',
  );

  print('final tests passed');
}
